export async function seedIbgeMunicipiosIfEmpty() {
  const [row] = await db.select({ count: sql<number>`count(*)::int` }).from(ibgeMunicipiosTable);
  if ((row?.count ?? 0) > 0) return;

  console.log("[seed-ibge] Tabela vazia — buscando municípios da API IBGE...");
  try {
    const resp = await fetch("https://servicodados.ibge.gov.br/api/v1/localidades/municipios");
    if (!resp.ok) throw new Error(`HTTP ${resp.status}`);
    const data: any[] = await resp.json();

    const batchSize = 200;
    for (let i = 0; i < data.length; i += batchSize) {
      const batch = data.slice(i, i + batchSize);
      const values = batch.map((m: any) => {
        const uf = m.microrregiao?.mesorregiao?.UF?.sigla
          ?? m["regiao-imediata"]?.["regiao-intermediaria"]?.UF?.sigla
          ?? "";
        const nome = m.nome.replace(/'/g, "''");
        return `('${String(m.id)}', '${nome}', '${uf}')`;
      }).join(", ");
      await db.execute(sql.raw(
        `INSERT INTO ibge_municipios (codigo, nome, uf) VALUES ${values} ON CONFLICT (codigo) DO NOTHING`
      ));
    }
    console.log(`[seed-ibge] ${data.length} municípios inseridos.`);
  } catch (err) {
    console.warn("[seed-ibge] Falha ao buscar dados IBGE:", err);
  }
}